mapper.select:
SELECT o.order_id, o.member_idx, o.order_date, o.total_price, o.status, MIN(b.book_id) AS book_id, MIN(b.book_title) AS book_title, MIN(b.cover_image) AS book_cover, d.status_code AS delivery_status, COUNT(*) AS book_count FROM orders o JOIN orderitem oi ON o.order_id = oi.order_id JOIN book b ON oi.book_id = b.book_id
JOIN ( SELECT d1.order_id, d1.status_code FROM delivery d1 JOIN ( SELECT order_id, MAX(delivery_id) AS max_id FROM delivery GROUP BY order_id ) d2 ON d1.order_id = d2.order_id AND d1.delivery_id = d2.max_id ) d ON o.order_id = d.order_id
WHERE o.member_idx = #{member_idx}
GROUP BY o.order_id ORDER BY o.order_id DESC LIMIT #{offset}, #{perPageNum}

mapper.update:
UPDATE orders
SET status = #{status}
WHERE order_id = #{order_id}

mapper.select:
SELECT o.order_id, o.member_idx, o.order_date, o.total_price, o.status, m.member_id, m.member_name, MIN(b.book_title) AS book_title, MIN(b.cover_image) AS book_cover, d.status_code AS delivery_status, d.tracking_number, d.shipper_name, COUNT(*) AS book_count FROM orders o JOIN member m ON o.member_idx = m.member_idx JOIN orderitem oi ON o.order_id = oi.order_id JOIN book b ON oi.book_id = b.book_id
JOIN ( SELECT d1.order_id, d1.status_code, d1.tracking_number, d1.shipper_name FROM delivery d1 JOIN ( SELECT order_id, MAX(delivery_id) AS max_id FROM delivery GROUP BY order_id ) d2 ON d1.order_id = d2.order_id AND d1.delivery_id = d2.max_id ) d ON o.order_id = d.order_id
AND m.member_id LIKE CONCAT('%', #{member_id}, '%')
AND o.status = #{payment_status}
AND d.status_code = #{delivery_status}
GROUP BY o.order_id ORDER BY o.order_id DESC LIMIT #{offset}, #{perPageNum}

SELECT COUNT(*)
FROM orders o
JOIN member m ON o.member_idx = m.member_idx


    AND m.member_id LIKE CONCAT('%', #{member_id}, '%')


    AND o.status = #{payment_status}


    AND EXISTS (
      SELECT 1 FROM delivery d
      WHERE d.order_id = o.order_id
      AND d.status_code = #{delivery_status}
    )

